149:     public SaslServerAuthenticator(Map<String, ?> configs,
150:                                    Map<String, AuthenticateCallbackHandler> callbackHandlers,
151:                                    String connectionId,
152:                                    Map<String, Subject> subjects,
153:                                    KerberosShortNamer kerberosNameParser,
154:                                    ListenerName listenerName,
155:                                    SecurityProtocol securityProtocol,
156:                                    TransportLayer transportLayer,
157:                                    Map<String, Long> connectionsMaxReauthMsByMechanism,
158:                                    ChannelMetadataRegistry metadataRegistry,
159:                                    Time time,
160:                                    Supplier<ApiVersionsResponse> apiVersionSupplier) {
161:         this.callbackHandlers = callbackHandlers;
162:         this.connectionId = connectionId;
163:         this.subjects = subjects;
164:         this.listenerName = listenerName;
165:         this.securityProtocol = securityProtocol;
166:         this.enableKafkaSaslAuthenticateHeaders = false;
167:         this.transportLayer = transportLayer;
168:         this.connectionsMaxReauthMsByMechanism = connectionsMaxReauthMsByMechanism;
169:         this.time = time;
170:         this.reauthInfo = new ReauthInfo();
171:         this.metadataRegistry = metadataRegistry;
172:         this.apiVersionSupplier = apiVersionSupplier;
173: 
174:         this.configs = configs;
175:         @SuppressWarnings("unchecked")
176:         List<String> enabledMechanisms = (List<String>) this.configs.get(BrokerSecurityConfigs.SASL_ENABLED_MECHANISMS_CONFIG);
177:         if (enabledMechanisms == null || enabledMechanisms.isEmpty())
178:             throw new IllegalArgumentException("No SASL mechanisms are enabled");
179:         this.enabledMechanisms = new ArrayList<>(new HashSet<>(enabledMechanisms));
180:         for (String mechanism : this.enabledMechanisms) {
181:             if (!callbackHandlers.containsKey(mechanism))
182:                 throw new IllegalArgumentException("Callback handler not specified for SASL mechanism " + mechanism);
183:             if (!subjects.containsKey(mechanism))
184:                 throw new IllegalArgumentException("Subject cannot be null for SASL mechanism " + mechanism);
185:             LOG.trace("{} for mechanism={}: {}", BrokerSecurityConfigs.CONNECTIONS_MAX_REAUTH_MS_CONFIG, mechanism,
186:                     connectionsMaxReauthMsByMechanism.get(mechanism));
187:         }
188: 
189:         // Note that the old principal builder does not support SASL, so we do not need to pass the
190:         // authenticator or the transport layer
191:         this.principalBuilder = ChannelBuilders.createPrincipalBuilder(configs, kerberosNameParser, null);
192: 
193:         saslAuthRequestMaxReceiveSize = (Integer) configs.get(BrokerSecurityConfigs.SASL_SERVER_MAX_RECEIVE_SIZE_CONFIG);
194:         if (saslAuthRequestMaxReceiveSize == null)
195:             saslAuthRequestMaxReceiveSize = BrokerSecurityConfigs.DEFAULT_SASL_SERVER_MAX_RECEIVE_SIZE;
196:     }
197: 
198:     private void createSaslServer(String mechanism) throws IOException {
199:         this.saslMechanism = mechanism;
200:         Subject subject = subjects.get(mechanism);
201:         final AuthenticateCallbackHandler callbackHandler = callbackHandlers.get(mechanism);
202:         if (mechanism.equals(SaslConfigs.GSSAPI_MECHANISM)) {
203:             saslServer = createSaslKerberosServer(callbackHandler, configs, subject);
204:         } else {
205:             try {
206:                 saslServer = Subject.doAs(subject, (PrivilegedExceptionAction<SaslServer>) () ->
207:                     Sasl.createSaslServer(saslMechanism, "kafka", serverAddress().getHostName(), configs, callbackHandler));
208:                 if (saslServer == null) {
209:                     throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism);
210:                 }
211:             } catch (PrivilegedActionException e) {
212:                 throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication with server mechanism " + saslMechanism, e.getCause());
213:             }
214:         }
215:     }
216: 
217:     private SaslServer createSaslKerberosServer(final AuthenticateCallbackHandler saslServerCallbackHandler, final Map<String, ?> configs, Subject subject) throws IOException {
218:         // server is using a JAAS-authenticated subject: determine service principal name and hostname from kafka server's subject.
219:         final String servicePrincipal = SaslClientAuthenticator.firstPrincipal(subject);
220:         KerberosName kerberosName;
221:         try {
222:             kerberosName = KerberosName.parse(servicePrincipal);
223:         } catch (IllegalArgumentException e) {
224:             throw new KafkaException("Principal has name with unexpected format " + servicePrincipal);
225:         }
226:         final String servicePrincipalName = kerberosName.serviceName();
227:         final String serviceHostname = kerberosName.hostName();
228: 
229:         LOG.debug("Creating SaslServer for {} with mechanism {}", kerberosName, saslMechanism);
230: 
231:         try {
232:             return Subject.doAs(subject, (PrivilegedExceptionAction<SaslServer>) () ->
233:                     Sasl.createSaslServer(saslMechanism, servicePrincipalName, serviceHostname, configs, saslServerCallbackHandler));
234:         } catch (PrivilegedActionException e) {
235:             throw new SaslException("Kafka Server failed to create a SaslServer to interact with a client during session authentication", e.getCause());
236:         }
237:     }
