350:         SaslServerAuthenticator previousSaslServerAuthenticator = (SaslServerAuthenticator) reauthenticationContext.previousAuthenticator();
351:         reauthInfo.reauthenticating(previousSaslServerAuthenticator.saslMechanism,
352:                 previousSaslServerAuthenticator.principal(), reauthenticationContext.reauthenticationBeginNanos());
353:         previousSaslServerAuthenticator.close();
354:         netInBuffer = saslHandshakeReceive;
355:         LOG.debug("Beginning re-authentication: {}", this);
356:         netInBuffer.payload().rewind();
357:         setSaslState(SaslState.REAUTH_PROCESS_HANDSHAKE);
358:         authenticate();
